Association Heatmap

IS_INDEX_ORDER = [
  "inv-FIns", "inv-HOMA-IR", "Raynaud SI", "QUICKI", "Belfiore basal",
  "inv-FIns/FGlu", "ISI basal", "Bennett SI", "Avignon SI0", "FIRI",
  "inv-Ins 120", "inv-Glu 120", "ISI 120", "inv-Ins/Glu120", "Gutt Index",
  "Avignon SI120", "Avignon SIM", "Stumvoll Modi", "Stumvoll Dem", "inv-IFC",
  "BIGTT SI", "Matsuda", "Matsuda AUC"
]

// Group → colour band for background stripe
GROUP_COLOR = ({
  "Fasting":       "#f0f4ff",
  "OGTT,0-120":    "#fff7f0",
  "OGTT,0-30-120": "#f0fff4"
})

rawData = analysisType === "BMI-Adjusted"
  ? transpose(data_bmi)
  : transpose(data_no_bmi)

filtered = rawData.filter(d =&gt; {
  const q = searchQuery.toLowerCase().trim()
  const matchSearch =
    q === "" ||
    (d.nearest_gene  && d.nearest_gene.toLowerCase().includes(q))  ||
    (d.index_variant && d.index_variant.toLowerCase().includes(q)) ||
    (d.gene_snp_ra   && d.gene_snp_ra.toLowerCase().includes(q))
  const matchGroup = indexGroups.includes(d.index_group)
  const matchPval  = +d.pvalue &lt;= pvalThresh
  const matchBeta  = Math.abs(+d.beta) &gt;= betaMin
  return matchSearch && matchGroup && matchPval && matchBeta
})

// Variants in their original (clustered) order, deduplicated
uniqueVariants = [...new Set(filtered.map(d =&gt; d.gene_snp_ra))]

// Visible x-axis indices
visibleIndices = IS_INDEX_ORDER.filter(idx =&gt; {
  const fasting = ["inv-FIns","inv-HOMA-IR","Raynaud SI","QUICKI","Belfiore basal",
                   "inv-FIns/FGlu","ISI basal","Bennett SI","Avignon SI0","FIRI"]
  const ogtt2   = ["inv-Ins 120","inv-Glu 120","ISI 120","inv-Ins/Glu120","Gutt Index",
                   "Avignon SI120","Avignon SIM","Stumvoll Modi","Stumvoll Dem","inv-IFC"]
  if (fasting.includes(idx)) return indexGroups.includes("Fasting")
  if (ogtt2.includes(idx))   return indexGroups.includes("OGTT,0-120")
  return indexGroups.includes("OGTT,0-30-120")
})

cellH    = uniqueVariants.length &lt;= 50 ? 18 : uniqueVariants.length &lt;= 200 ? 12 : 8
plotH    = Math.max(400, uniqueVariants.length * cellH + 140)
cellW    = 28
plotW    = Math.max(600, visibleIndices.length * cellW + 280)
leftMarg = Math.min(280, Math.max(160,
             Math.max(...uniqueVariants.map(s =&gt; s.length)) * 6))















































































Plot.plot({
  width:        plotW,
  height:       plotH,
  marginLeft:   leftMarg,
  marginBottom: 110,
  marginRight:  80,
  style: { background: "#fafafa", fontFamily: "system-ui, sans-serif", fontSize: "11px" },

  color: {
    type:    "diverging",
    scheme:  "RdBu",
    pivot:   0,
    domain:  [-0.02, 0.02],
    legend:  true,
    label:   "Effect size (β)",
    reverse: true    // red = positive (higher IS)
  },

  x: {
    domain:     visibleIndices,
    tickRotate: -55,
    label:      "Insulin Sensitivity Index",
    labelAnchor:"right"
  },

  y: {
    domain:  uniqueVariants,
    label:   "Gene – Variant – Risk allele",
    tickSize: 0
  },

  marks: [
    // Main heatmap cells
    Plot.cell(filtered, {
      x:     "is_index",
      y:     "gene_snp_ra",
      fill:  d =&gt; +d.beta,
      title: d =&gt; [
        `Gene:        ${d.nearest_gene}`,
        `Variant:     ${d.index_variant}`,
        `Risk allele: ${d.t_2_d_risk_allele}`,
        `IS Index:    ${d.is_index}  (${d.index_group})`,
        `β =          ${(+d.beta).toFixed(5)}`,
        `p =          ${(+d.pvalue).toExponential(3)}`
      ].join("\n"),
      stroke:      "#e0e0e0",
      strokeWidth: 0.4,
      rx: 1
    }),

    // Black border for nominally significant (p &lt; 0.05)
    sigHighlight
      ? Plot.cell(filtered.filter(d =&gt; +d.pvalue &lt; 0.05), {
          x:           "is_index",
          y:           "gene_snp_ra",
          stroke:      "#111",
          strokeWidth: 1.5,
          fill:        "none",
          rx: 1
        })
      : Plot.dot([], {}),   // no-op when toggle is off

    // White star for genome-wide / Bonferroni significant
    Plot.text(filtered.filter(d =&gt; +d.pvalue &lt; 1e-4), {
      x:          "is_index",
      y:          "gene_snp_ra",
      text:       () =&gt; "✶",
      fill:       "white",
      fontSize:   9,
      frameAnchor:"middle"
    })
  ]
})








Data Table

Inputs.table(filtered, {
  columns: [
    "nearest_gene", "index_variant", "t_2_d_risk_allele",
    "is_index", "index_group", "beta", "pvalue"
  ],
  header: {
    nearest_gene:     "Gene",
    index_variant:    "Variant (rsID)",
    t_2_d_risk_allele:"Risk Allele",
    is_index:         "IS Index",
    index_group:      "Index Group",
    beta:             "β (Effect Size)",
    pvalue:           "P-value"
  },
  format: {
    beta:   x =&gt; (+x).toFixed(5),
    pvalue: x =&gt; (+x).toExponential(3)
  },
  sort:    "pvalue",
  reverse: false,
  rows:    25
})
